                    <div className="flex items-center gap-2">
                      <div className="flex-1 h-2 bg-gray-600 rounded-full overflow-hidden">
                        <div className="h-full bg-gradient-to-r from-green-500 to-blue-500" style={{ width: '66%' }} />
                      </div>
                      <span className="text-sm font-medium">2/3 completed</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Profile Page */}
          {currentPage === 'profile' && (
            <div className="p-8">
              <div className="max-w-4xl mx-auto">
                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-8 mb-6`}>
                  <div className="flex items-center gap-6 mb-6">
                    <div className="w-24 h-24 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center text-white font-bold text-3xl">
                      {username ? username[0].toUpperCase() : 'U'}
                    </div>
                    <div>
                      <h2 className="text-2xl font-bold mb-2">{username || 'Anonymous'}</h2>
                      <p className="text-gray-400">Member since March 2024</p>
                      <p className="text-xs text-gray-500 mt-1">ID: {userId}</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                    <div className={`p-4 rounded-lg text-center ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                      <div className="text-3xl mb-2">🏆</div>
                      <div className="text-2xl font-bold">{xp}</div>
                      <div className="text-sm text-gray-400">Total XP</div>
                    </div>
                    <div className={`p-4 rounded-lg text-center ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                      <div className="text-3xl mb-2">🔥</div>
                      <div className="text-2xl font-bold">{streak}</div>
                      <div className="text-sm text-gray-400">Day Streak</div>
                    </div>
                    <div className={`p-4 rounded-lg text-center ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                      <div className="text-3xl mb-2">📚</div>
                      <div className="text-2xl font-bold">{completed.length}</div>
                      <div className="text-sm text-gray-400">Lessons Completed</div>
                    </div>
                  </div>

                  <div className="space-y-4">
                    <h3 className="text-lg font-bold">Achievements</h3>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      {[
                        { icon: '🎯', name: 'First Steps', earned: true },
                        { icon: '🐍', name: 'Python Beginner', earned: true },
                        { icon: '⚡', name: 'JavaScript Starter', earned: false },
                        { icon: '🌐', name: 'HTML Expert', earned: false },
                      ].map((achievement, idx) => (
                        <div key={idx} className={`p-3 rounded-lg text-center ${
                          achievement.earned
                            ? 'bg-yellow-500/20 border border-yellow-500/50'
                            : theme === 'dark' ? 'bg-gray-700 opacity-50' : 'bg-gray-100 opacity-50'
                        }`}>
                          <div className="text-2xl mb-1">{achievement.icon}</div>
                          <div className="text-xs font-medium">{achievement.name}</div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6`}>
                  <h3 className="text-xl font-bold mb-4">Learning Statistics</h3>
                  <div className="space-y-3">
                    {LANGUAGES.map((lang) => {
                      const langCompleted = completed.filter(c => c.startsWith(lang.id)).length;
                      return (
                        <div key={lang.id} className={`flex items-center justify-between p-3 rounded-lg ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                          <div className="flex items-center gap-3">
                            <span className="text-xl">{lang.icon}</span>
                            <span className="font-medium">{lang.name}</span>
                          </div>
                          <span className="text-sm text-gray-400">{langCompleted}/{LESSONS[lang.id].length} lessons</span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </>
  );
}

export default App;
